@media (prefers-reduced-motion: reduce) {
  .banner {
    animation: fadeIn 0.3s ease-out;
  }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.skeleton-line {
  height: 1rem;
  margin-bottom: 0.75rem;
  background: #eee;
  border-radius: 4px;
  position: relative;
  overflow: hidden;
}
.skeleton-line::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent);
  background-size: 200px 100%;
  animation: shimmer 1.5s infinite;
}
.skeleton-line.short { width: 60%; }

@keyframes shimmer {
  0% { background-position: -200px 0; }
  100% { background-position: calc(200px + 100%) 0; }
}

@media (prefers-reduced-motion: reduce) {
  .skeleton-line::after { animation: none; }
}

.hero { position: relative; overflow: hidden; min-height: 80vh; }
.hero-bg {
  position: absolute; inset: 0;
  background: url('bg.jpg') center/cover fixed;
}
.floating-icon {
  animation: float 3s ease-in-out infinite;
}
[data-reveal] {
  animation: revealUp 0.8s ease-out forwards;
}
.cta {
  transition: transform 0.3s, background-color 0.3s;
}
.cta:hover { transform: scale(1.05); }

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-20px); }
}
@keyframes revealUp {
  from { opacity: 0; transform: translateY(40px); }
  to { opacity: 1; transform: translateY(0); }
}

@media (prefers-reduced-motion: reduce) {
  .hero-bg { background-attachment: scroll; }
  .floating-icon { animation: none; }
  [data-reveal] { animation: none; opacity: 1; transform: none; }
  .cta:hover { transform: none; }
}
